function R_DrawColumn(): void {
  const count = dc_yh - dc_yl;
  if (count < 0) return;
  if (dc_x >= SCREENWIDTH || dc_yl < 0 || dc_yh >= SCREENHEIGHT) {
    throw new RangeError(`R_DrawColumn: bad parameters x=${dc_x} yl=${dc_yl} yh=${dc_yh}`);
  }
  let dest = ylookup[dc_yl] + columnofs[dc_x];
  let frac = dc_texturemid + (dc_yl - centery) * dc_iscale;
  for (let i = 0; i <= count; i++, dest += SCREENWIDTH, frac += dc_iscale) {
    dest[0] = dc_colormap[dc_source[frac >> FRACBITS]];
  }
}
